const data = [];
for (let x = 0; x < 12; x++) {
  for (let y = 0; y < 24; y++) {
    data.push({
      hour: x,
      day: y,
      intensity: Math.round(50 + 50 * Math.sin(x / 2) * Math.cos(y / 3)),
