import { Chart } from '@antv/g2';

const data = [
  { resource: 'CPU使用率', ranges: 100, measures: 65, target: 80 },
  { resource: '内存使用率', ranges: 100, measures: 45, target: 70 },
  { resource: '磁盘使用率', ranges: 100, measures: 88, target: 85 },
  { resource: '网络带宽', ranges: 100, measures: 72, target: 75 },
];

// 数据转换：为每个资源生成区间条和目标线数据
const intervalData = data.map(d => ({
  resource: d.resource,
  type: 'range',
  start: 0,
  end: d.ranges,
}));

const pointData = data.map(d => ({
  resource: d.resource,
  type: 'measure',
  value: d.measures,
  exceed: d.measures > d.target, // 是否超出目标
}));

const targetData = data.map(d => ({
  resource: d.resource,
  type: 'target',
  value: d.target,
}));

const chart = new Chart({
  container: 'container',
  width: 800,
  height: 400,
}));

chart.options({
  type: 'view',
  children: [
    // 背景区间条
    {
      type: 'interval',
      data: intervalData,
      encode: {
        x: 'resource',
        y: 'start',
        y1: 'end',
      },
      style: {
        fill: '#e0e0e0',
      },
      axis: {
        y: {
          title: '使用率 (%)',
        },
      },
    },
    // 当前使用率点
    {
      type: 'point',
      data: pointData,
      encode: {
        x: 'resource',
        y: 'value',
        shape: 'circle',
        color: (d) => d.exceed ? '#f5222d' : '#52c41a', // 超出红色，未超出绿色
      },
      style: {
        r: 6,
        lineWidth: 2,
        stroke: '#fff',
      },
      labels: [
        {
          text: 'value',
          position: 'right',
          dx: 10,
          formatter: (d) => `${d.value}%`,
        },
      ],
    },
    // 目标值线
    {
      type: 'point',
      data: targetData,
      encode: {
        x: 'resource',
        y: 'value',
        shape: 'tick',
        color: '#1890ff',
      },
      style: {
        size: 20,
      },
      labels: [
        {
          text: 'value',
          position: 'top',
          dy: -10,
          formatter: (d) => `目标: ${d.value}%`,
        },
      ],
    },
  ],
  coordinate: {
    transform: [{ type: 'transpose' }], // 横向排列
  },
});

chart.render();

