import { Chart } from '@antv/g2';

// 输入数据
const inputData = [
  { text: 'A', value: 12000 },
  { text: 'B', value: 9800 },
  { text: 'C', value: 6789 },
  { text: 'D', value: 4569 }
];

// 1. 计算转换率
const processData = inputData.map((d, i) => {
  const rate = i === 0 ? 1 : d.value / inputData[i - 1].value;
  return {
    ...d,
    rate: rate,
    rateText: i === 0 ? '' : `${(rate * 100).toFixed(2)}%`
  };
});

// 2. 构造对称漏斗图所需数据（复制一份并取负值）
const symmetricData = processData.flatMap(d => [
  { ...d, side: 'right' },
  { ...d, side: 'left', value: -d.value }
]);

// 3. 构造连接线数据（仅右侧正值）
const lineData = processData;

// 4. 构造总转化率文本
const totalRate = (processData[processData.length - 1].value / processData[0].value);
const totalRateText = `总转化率: ${(totalRate * 100).toFixed(2)}%`;

const chart = new Chart({
  container: 'container',
  width: 800,
  height: 500,
  paddingLeft: 120,
  paddingBottom: 80
});

chart.options({
