import { Chart } from '@antv/g2';

// 生成更多模拟数据以满足 KDE 要求
const generateData = () => {
  const groups = ['A', 'B', 'C'];
  const baseValues = { A: 15, B: 35, C: 25 };
  const data = [];

  groups.forEach(group => {
    const base = baseValues[group];
    for (let i = 0; i < 50; i++) {
      // 添加一些噪声以模拟真实分布
      const value = base + (Math.random() - 0.5) * 10;
      data.push({ group, value });
    }
  });

  return data;
};

