  transform: [{ type: 'stackY' }],
  coordinate: { 
    type: 'theta',
    outerRadius: 0.8
  },
  interaction: {
    elementHoverScale: true  // 鼠标悬停放大效果
  },
  labels: [{
    text: (d) => {
      const percentage = ((d.count / total) * 100).toFixed(1);
      return `${percentage}%`;
    },
    position: 'outside',
    connector: true,
    style: {
      fontSize: (d) => {
        const percentage = (d.count / total) * 100;
        // 根据百分比调整字体大小，最小12px，最大20px
        return Math.min(20, Math.max(12, percentage));
      },
      fill: (d) => {
        // 根据数值大小调整字体颜色，突出大值
        return d.count > 20 ? '#1890ff' : '#666';
      }
    }
  }],
  legend: {
    color: { 
      position: 'bottom', 
      layout: { justifyContent: 'center' } 
    }
  }
});

chart.render();

