import { Chart } from '@antv/g2';

const data = [
  { country: 'US', stage: 'Awareness', value: 100000 },
  { country: 'EU', stage: 'Awareness', value: 80000 },
  { country: 'US', stage: 'Consideration', value: 65000 },
  { country: 'EU', stage: 'Consideration', value: 55000 },
  { country: 'US', stage: 'Preference', value: 40000 },
  { country: 'EU', stage: 'Preference', value: 38000 },
  { country: 'US', stage: 'Purchase', value: 18000 },
  { country: 'EU', stage: 'Purchase', value: 21000 }
];

// 数据处理：为了实现对称的横向漏斗图，我们需要将一个国家的数据设置为负值
const processedData = data.map(d => ({
  ...d,
  // 将 US 的数据设为负值，这样在转置坐标系中就会向左延伸
  displayValue: d.country === 'US' ? -d.value : d.value
}));

const chart = new Chart({
  container: 'container',
  width: 800,
  height: 500,
});

chart.options({
  type: 'view',
  data: processedData,
  coordinate: { transform: [{ type: 'transpose' }] }, // 转置坐标系实现横向布局
  children: [
    {
      type: 'interval',
      encode: {
        x: 'stage',
        y: 'displayValue',
        color: 'country',
      },
      transform: [{ type: 'dodgeX' }], // 分组柱状图
      labels: [{ 
        text: 'value',
        formatter: (d) => d.value.toLocaleString(), // 格式化标签显示
        position: 'outside' // 标签位置在柱子外侧
      }],
      tooltip: {
        items: [
          { channel: 'x', name: '阶段' },
          { channel: 'y', name: '国家' },
          { field: 'value', name: '价值', valueFormatter: (v) => v.toLocaleString() }
        ]
      },
      style: {
        radius: 4, // 圆角
        fillOpacity: 0.8 // 透明度
      }
    }
  ],
  axis: {
    y: {
      labelFormatter: (value) => Math.abs(value).toLocaleString(), // 显示绝对值
      title: '用户价值'
    },
    x: {
      title: '用户阶段'
    }
  },
  legend: {
    position: 'top'
  }
});

chart.render();

