import { Chart } from '@antv/g2';

const chart = new Chart({
  container: 'container',
  width: 600,
  height: 500,
});

// 原始数据
const rawData = [
  { level: '浏览商品', uv: 20000 },
  { level: '加入购物车', uv: 8000, highlight: true },
  { level: '结算页', uv: 3000, highlight: true },
  { level: '支付成功', uv: 1200 },
  { level: '复购', uv: 400 },
];

// 计算转化率并添加标签文本
const processData = (data) => {
  return data.map((d, i) => {
    if (d.highlight) {
      const rate = i === 0 ? 100 : ((d.uv / data[i - 1].uv) * 100);
      return {
        ...d,
        rate: `${rate.toFixed(1)}%`,
        label: `⚠️ ${d.level}\n${d.rate || ''}`, // 警告符号 + 转化率
      };
    }
    return {
      ...d,
      label: `${d.level}\n${d.uv.toLocaleString()}`, // 原始 UV 值
    };
  });
};

const processedData = processData(rawData);

chart.options({
  type: 'view',
  data: processedData,
  axis: false,
  legend: false,
  children: [
    // 漏斗图主体
    {
      type: 'interval',
      encode: {
        x: 'level',
        y: 'uv',
        color: 'level',
        shape: 'funnel',
      },
      transform: [{ type: 'symmetryY' }],
      coordinate: { transform: [{ type: 'transpose' }] },
      style: { stroke: '#fff', lineWidth: 1 },
      labels: [
        {
          text: (d) => {
            if (d.highlight) {
              const rate = ((d.uv / processedData.find(p => p.level === (processedData[processedData.indexOf(d) - 1]?.level))?.uv || d.uv) * 100).toFixed(1);
              return `⚠️ ${d.level}\n${rate}%`;
            }
            return `${d.level}\n${d.uv.toLocaleString()}`;
          },
          position: 'inside',
          style: {
            fill: '#fff',
            fontWeight: 'bold',
            textAlign: 'center',
            textBaseline: 'middle',
            fontSize: 12,
          },
        },
      ],
    },
  ],
});

chart.render();

