import { Chart } from "@antv/g2";

// 生成模拟空气质量年度数据（按月+昼夜分段）
const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const sections = ['Day','Night'];
const data = [];
months.forEach((month, mIdx) => {
  sections.forEach(section => {
    for (let day = 1; day <= 15; day++) {
      const baseAQI = 50 + Math.sin((mIdx + day/30) * Math.PI/6) * 30; // 季节性基线
      const sectionAdjust = section === 'Day' ? 15 : -10;                // 昼夜差异
      const noise = (Math.random() - 0.5) * 15;
      data.push({
        segment: `${month} ${section}`,
        time: `${month}-${day.toString().padStart(2,'0')}`,
        aqi: Math.max(10, Math.min(150, baseAQI + sectionAdjust + noise)),
        section
      });
    }
  });
});

const chart = new Chart({ container: "container", autoFit: true, height: 520 });
chart.options({
  type: "interval",
  data,
  encode: {
    x: "time",
    y: "aqi",
    color: "aqi",
    series: "section"
  },
  scale: {
    color: {
      type: "threshold",
      domain: [0, 50, 100, 150],
      range: ["#1a9850", "#fee08b", "#d73027", "#762a83"]
    }
  },
  coordinate: {
    type: "helix",
    startAngle: Math.PI,
    endAngle: 7 * Math.PI,
    innerRadius: 0.2,
    outerRadius: 0.9,
  },
  style: {
    fillOpacity: 0.75,
    stroke: "#fff",
    lineWidth: 0.5
  },

