import { Chart } from '@antv/g2';

// 原始数据
const data = [
  { x: 'Parking Difficult', value: 95 },
  { x: 'Sales Rep was Rude', value: 60 },
  { x: 'Poor Lighting', value: 45 },
  { x: 'Layout Confusing', value: 37 },
  { x: 'Sizes Limited', value: 30 },
  { x: 'Clothing Faded', value: 27 },
  { x: 'Clothing Shrank', value: 18 }
];

// 计算总和
const total = data.reduce((sum, d) => sum + d.value, 0);

// 数据转换：计算百分比和累积百分比，并添加颜色标识
const transformedData = data
  .map(d => ({
    ...d,
    percentage: (d.value / total) * 100
  }))
  .sort((a, b) => b.percentage - a.percentage) // 按百分比降序排序
  .map((d, i, arr) => {
    const cumulativePercentage = arr.slice(0, i + 1).reduce((sum, curr) => sum + curr.percentage, 0);
    return {
      ...d,
      cumulativePercentage,
      // 如果单项占比小于10%，标记为true，用于颜色区分
      isLowPercentage: d.percentage < 10
    };
  });

const chart = new Chart({
  container: 'container',
  width: 800,
  height: 500,
  paddingLeft: 60,
  paddingBottom: 80
});

chart.options({
  type: 'view',
  data: transformedData,
  children: [
    // 柱状图：显示每个问题的频数
    {
      type: 'interval',
      encode: {
        x: 'x',
        y: 'value',
        color: (d) => d.isLowPercentage ? 'low' : 'high'
      },
      scale: {
        color: {
          domain: ['low', 'high'],
          range: ['#FACC15', '#2563EB']
        }
      },
      axis: {
        x: { title: '问题类型' },
        y: { title: '频数' }
      },
      labels: [{ text: 'value', position: 'insideTop', textAlign: 'center', dy: -10 }]
    },
    // 折线图：显示累积百分比
    {
      type: 'line',
      encode: {
        x: 'x',
        y: 'cumulativePercentage'
      },
      scale: {
        y: {
          domain: [0, 100]
        }
      },
      style: {
        stroke: '#EF4444',
        lineWidth: 2
      },
      axis: {
        y: {
          position: 'right',
          title: '累积百分比 (%)',
          labelFormatter: (d) => `${d}%`
        }
      }
    },
    // 点图：显示累积百分比的具体数值点
    {
      type: 'point',
      encode: {
        x: 'x',
        y: 'cumulativePercentage'
      },
      style: {
        fill: '#EF4444',
        r: 4
      },
      labels: [{
        text: (d) => `${d.cumulativePercentage.toFixed(1)}%`,
        position: 'top',
        dy: -10,
        fill: '#EF4444',
        fontSize: 12
      }]
    }
  ],
  interaction: {
    elementHighlight: true
  }
});

chart.render();

